package gitlaboauth

import (
	"context"
	"net/http"
	"strconv"

	"golang.org/x/oauth2"

	"github.com/sourcegraph/log"

	"github.com/sourcegraph/sourcegraph/cmd/frontend/auth"
	"github.com/sourcegraph/sourcegraph/cmd/frontend/internal/auth/oauth"
	"github.com/sourcegraph/sourcegraph/cmd/frontend/internal/auth/providers"
	"github.com/sourcegraph/sourcegraph/cmd/frontend/internal/auth/session"
	"github.com/sourcegraph/sourcegraph/internal/actor"
	"github.com/sourcegraph/sourcegraph/internal/database"
	"github.com/sourcegraph/sourcegraph/internal/extsvc"
	"github.com/sourcegraph/sourcegraph/internal/extsvc/gitlab"
	"github.com/sourcegraph/sourcegraph/internal/telemetry/telemetryrecorder"
	"github.com/sourcegraph/sourcegraph/lib/errors"
)

type sessionIssuerHelper struct {
	*extsvc.CodeHost
	logger      log.Logger
	clientID    string
	db          database.DB
	allowSignup *bool
	allowGroups []string
	scopes      []string
}

func (s *sessionIssuerHelper) AuthAuditEntity() string {
	return "auth.gitlab"
}

func (s *sessionIssuerHelper) GetServiceID() string {
	return s.ServiceID
}

func (s *sessionIssuerHelper) GetServiceType() string {
	return s.ServiceType
}

func (s *sessionIssuerHelper) ExtractValidationIdentity(ctx context.Context, token *oauth2.Token) (*oauth.ValidationIdentityInfo, error) {
	ctx, err := s.populateUserContext(ctx, token)
	if err != nil {
		return nil, err
	}

	info := &oauth.ValidationIdentityInfo{}
	user, err := UserFromContext(ctx)
	if err != nil {
		return nil, err
	}

	info.Subject = strconv.FormatInt(int64(user.ID), 10)
	info.Email = user.Email
	info.Username = user.Username
	info.DisplayName = user.Name

	if info.Email == "" {
		info.Warnings = append(info.Warnings, "No email returned for this GitLab account")
	}

	provider := gitlab.NewClientProvider(extsvc.URNGitLabOAuth, s.BaseURL, nil)
	glClient := provider.GetOAuthClient(token.AccessToken)
	userBelongsToAllowedGroups, err := s.verifyUserGroups(ctx, glClient)
	if err != nil {
		return nil, err
	}
	if !userBelongsToAllowedGroups {
		info.Warnings = append(info.Warnings, "User does not belong to any of the configured allowed GitLab groups")
	}

	return info, nil
}

func (s *sessionIssuerHelper) GetOrCreateUser(ctx context.Context, token *oauth2.Token) (result *oauth.SessionIssuerHelperResult, safeErrMsg string, err error) {
	ctx, err = s.populateUserContext(ctx, token)
	if err != nil {
		return nil, "Could not read GitLab user from callback request.", err
	}

	gUser, err := UserFromContext(ctx)
	if err != nil {
		return nil, "Could not read GitLab user from callback request.", errors.Wrap(err, "could not read user from context")
	}

	provider := gitlab.NewClientProvider(extsvc.URNGitLabOAuth, s.BaseURL, nil)
	glClient := provider.GetOAuthClient(token.AccessToken)

	// 🚨 SECURITY: Ensure that the user is part of one of the allowed groups or subgroups when the allowGroups option is set.
	userBelongsToAllowedGroups, err := s.verifyUserGroups(ctx, glClient)
	if err != nil {
		message := "Error verifying user groups."
		return nil, message, err
	}

	if !userBelongsToAllowedGroups {
		message := "User does not belong to allowed GitLab groups or subgroups."
		return nil, message, errors.New(message)
	}

	// AllowSignup defaults to true when not set to preserve the existing behavior.
	signupAllowed := s.allowSignup == nil || *s.allowSignup

	var data extsvc.AccountData
	if err := gitlab.SetExternalAccountData(&data, gUser, token, s.scopes); err != nil {
		return nil, "", err
	}

	recorder := telemetryrecorder.New(s.db)

	// Unlike with GitHub, we can *only* use the primary email to resolve the user's identity,
	// because the GitLab API does not return whether an email has been verified. The user's primary
	// email on GitLab is always verified, so we use that.
	authResult, safeErrMsg, err := auth.GetAndSaveUser(ctx, s.logger, s.db, recorder, auth.GetAndSaveUserOp{
		UserProps: database.NewUser{
			Username:        gUser.Username,
			Email:           gUser.Email,
			EmailIsVerified: gUser.Email != "",
			DisplayName:     gUser.Name,
			AvatarURL:       gUser.AvatarURL,
		},
		ExternalAccount: extsvc.AccountSpec{
			ServiceType: s.ServiceType,
			ServiceID:   s.ServiceID,
			ClientID:    s.clientID,
			AccountID:   strconv.FormatInt(int64(gUser.ID), 10),
		},
		ExternalAccountData: data,
		CreateIfNotExist:    signupAllowed,
	})
	if err != nil {
		return nil, safeErrMsg, err
	}

	return &oauth.SessionIssuerHelperResult{
		NewUserCreated:    authResult.NewUserCreated,
		Actor:             actor.FromUser(authResult.UserID),
		ExternalAccountID: authResult.ExternalAccountID,
	}, "", nil
}

func (s *sessionIssuerHelper) DeleteStateCookie(w http.ResponseWriter, r *http.Request) {
	session.SetData(s.db, w, r, "oauthState", "")
}

func (s *sessionIssuerHelper) SessionData(token *oauth2.Token) oauth.SessionData {
	return oauth.SessionData{
		ID: providers.ConfigID{
			ID:   s.ServiceID,
			Type: s.ServiceType,
		},
		AccessToken: token.AccessToken,
		TokenType:   token.Type(),
		// TODO(beyang): store and use refresh token to auto-refresh sessions
	}
}

func (s *sessionIssuerHelper) populateUserContext(ctx context.Context, token *oauth2.Token) (context.Context, error) {
	if _, err := UserFromContext(ctx); err == nil {
		return ctx, nil
	}

	provider := gitlab.NewClientProvider(extsvc.URNGitLabOAuth, s.BaseURL, nil)
	glClient := provider.GetOAuthClient(token.AccessToken)
	user, err := glClient.GetUser(ctx, "")
	if err != nil {
		return ctx, errors.Wrap(err, "unable to get GitLab user")
	}
	if user == nil || user.ID == 0 {
		return ctx, errors.New("unable to get GitLab user: bad user info")
	}
	return WithUser(ctx, user), nil
}

// verifyUserGroups checks whether the authenticated user belongs to one of the GitLab groups when the allowGroups option is set.
func (s *sessionIssuerHelper) verifyUserGroups(ctx context.Context, glClient *gitlab.Client) (bool, error) {
	if len(s.allowGroups) == 0 {
		return true, nil
	}

	allowed := make(map[string]bool, len(s.allowGroups))
	for _, group := range s.allowGroups {
		allowed[group] = true
	}

	var err error
	var gitlabGroups []*gitlab.Group
	hasNextPage := true

	for page := 1; hasNextPage; page++ {
		gitlabGroups, hasNextPage, err = glClient.ListGroups(ctx, page)
		if err != nil {
			return false, err
		}

		// Check the full path instead of name so we can better handle subgroups.
		for _, glGroup := range gitlabGroups {
			if allowed[glGroup.FullPath] {
				return true, nil
			}
		}
	}

	return false, nil
}

