func TestClient_GroupBasedProjectDiscovery_Validation(t *testing.T) {
	ctx := tenanttest.TestContext()

	t.Run("SearchProjectsForUser-limit-validation", func(t *testing.T) {
		c := newTestClient(t)

		t.Run("zero limit", func(t *testing.T) {
			_, _, _, err := c.SearchProjectsForUser(ctx, "test", 0, "")
