func TestClient_GetGroupsByIDs_EdgeCases(t *testing.T) {
	ctx := tenanttest.TestContext()

	t.Run("empty response handling", func(t *testing.T) {
		t.Cleanup(func() {
			MockGetGroupsByIDs = nil
		})
		MockGetGroupsByIDs = func(c *Client, ctx context.Context, ids []string) ([]*Group, error) {
			return []*Group{}, nil
		}

		c := newTestClient(t)
		groups, err := c.GetGroupsByIDs(ctx, []string{"999"})
		if err != nil {
			t.Fatal(err)
		}

		if len(groups) != 0 {
			t.Errorf("Expected 0 groups for empty response, got %d", len(groups))
		}
	})

	t.Run("error handling", func(t *testing.T) {
		t.Cleanup(func() {
			MockGetGroupsByIDs = nil
		})
		MockGetGroupsByIDs = func(c *Client, ctx context.Context, ids []string) ([]*Group, error) {
			return nil, errors.Wrapf(assert.AnError, "test error")
		}

		c := newTestClient(t)
		_, err := c.GetGroupsByIDs(ctx, []string{"1"})
		require.ErrorIs(t, err, assert.AnError)
	})

	t.Run("pagination", func(t *testing.T) {
		ctx := tenanttest.TestContext()

		createTestGroup := func(id string, name string) *gql.GroupConnectionFieldsNodesGroup {
			return &gql.GroupConnectionFieldsNodesGroup{
				GroupFields: gql.GroupFields{
					Id:          id,
					Name:        name,
					FullPath:    name,
					Description: "Test group",
					WebUrl:      "https://gitlab.com/" + name,
					AvatarUrl:   "",
					Visibility:  "private",
				},
			}
		}

		t.Run("single page response", func(t *testing.T) {
			mockClient := NewMockGraphqlClient()

			// Setup single page response
			mockClient.GetGroupsByIDsFunc.PushReturn(&gql.GetGroupsByIDsResponse{
				Groups: gql.GetGroupsByIDsGroupsGroupConnection{
					GroupConnectionFields: gql.GroupConnectionFields{
						Nodes: []gql.GroupConnectionFieldsNodesGroup{
							*createTestGroup("gid://gitlab/Group/1", "group1"),
							*createTestGroup("gid://gitlab/Group/2", "group2"),
						},
						PageInfo: gql.GroupConnectionFieldsPageInfo{
							PageInfoFields: gql.PageInfoFields{
								HasNextPage: false,
								EndCursor:   "cursor1",
							},
						},
						Count: 2,
					},
				},
			}, nil)

			c := newTestClientWithGraphQLMock(t, mockClient)
			groups, err := c.GetGroupsByIDs(ctx, []string{"1", "2"})
			require.NoError(t, err)
			require.Len(t, groups, 2)

			// Verify only one GraphQL call was made
			calls := mockClient.GetGroupsByIDsFunc.History()
			require.Len(t, calls, 1)

			// Verify the call parameters
			call := calls[0]
			require.Equal(t, []string{"gid://gitlab/Group/1", "gid://gitlab/Group/2"}, call.Arg1)
			require.Equal(t, 50, call.Arg2)
			require.Equal(t, "", call.Arg3) // No cursor for first page
		})

		t.Run("multi page response", func(t *testing.T) {
			mockClient := NewMockGraphqlClient()

			// First page
			mockClient.GetGroupsByIDsFunc.PushReturn(&gql.GetGroupsByIDsResponse{
				Groups: gql.GetGroupsByIDsGroupsGroupConnection{
					GroupConnectionFields: gql.GroupConnectionFields{
						Nodes: []gql.GroupConnectionFieldsNodesGroup{
							*createTestGroup("gid://gitlab/Group/1", "group1"),
							*createTestGroup("gid://gitlab/Group/2", "group2"),
						},
						PageInfo: gql.GroupConnectionFieldsPageInfo{
							PageInfoFields: gql.PageInfoFields{
								HasNextPage: true,
								EndCursor:   "cursor1",
							},
						},
						Count: 4,
					},
				},
			}, nil)

			// Second page
			mockClient.GetGroupsByIDsFunc.PushReturn(&gql.GetGroupsByIDsResponse{
				Groups: gql.GetGroupsByIDsGroupsGroupConnection{
					GroupConnectionFields: gql.GroupConnectionFields{
						Nodes: []gql.GroupConnectionFieldsNodesGroup{
							*createTestGroup("gid://gitlab/Group/3", "group3"),
							*createTestGroup("gid://gitlab/Group/4", "group4"),
						},
						PageInfo: gql.GroupConnectionFieldsPageInfo{
							PageInfoFields: gql.PageInfoFields{
								HasNextPage: false,
								EndCursor:   "cursor2",
							},
						},
						Count: 4,
					},
				},
			}, nil)

			c := newTestClientWithGraphQLMock(t, mockClient)
			groups, err := c.GetGroupsByIDs(ctx, []string{"1", "2", "3", "4"})
			require.NoError(t, err)
			require.Len(t, groups, 4)

			// Verify correct number of GraphQL calls
			calls := mockClient.GetGroupsByIDsFunc.History()
			require.Len(t, calls, 2)

			// Verify first call parameters
			call1 := calls[0]
			require.Equal(t, []string{"gid://gitlab/Group/1", "gid://gitlab/Group/2", "gid://gitlab/Group/3", "gid://gitlab/Group/4"}, call1.Arg1)
			require.Equal(t, 50, call1.Arg2)
			require.Equal(t, "", call1.Arg3) // No cursor for first page

			// Verify second call parameters
			call2 := calls[1]
			require.Equal(t, []string{"gid://gitlab/Group/1", "gid://gitlab/Group/2", "gid://gitlab/Group/3", "gid://gitlab/Group/4"}, call2.Arg1)
			require.Equal(t, 50, call2.Arg2)
			require.Equal(t, "cursor1", call2.Arg3) // Cursor from first page
		})

		t.Run("empty cursor protection", func(t *testing.T) {
			mockClient := NewMockGraphqlClient()

			// First page with hasNextPage=true but empty endCursor
			mockClient.GetGroupsByIDsFunc.PushReturn(&gql.GetGroupsByIDsResponse{
				Groups: gql.GetGroupsByIDsGroupsGroupConnection{
					GroupConnectionFields: gql.GroupConnectionFields{
						Nodes: []gql.GroupConnectionFieldsNodesGroup{
							*createTestGroup("gid://gitlab/Group/1", "group1"),
						},
						PageInfo: gql.GroupConnectionFieldsPageInfo{
							PageInfoFields: gql.PageInfoFields{
								HasNextPage: true,
								EndCursor:   "", // Empty cursor should break pagination
							},
						},
						Count: 1,
					},
				},
			}, nil)

			c := newTestClientWithGraphQLMock(t, mockClient)
			groups, err := c.GetGroupsByIDs(ctx, []string{"1"})
			require.NoError(t, err)
			require.Len(t, groups, 1)

			// Should only make one call due to empty cursor protection
			calls := mockClient.GetGroupsByIDsFunc.History()
			require.Len(t, calls, 1)
		})

		t.Run("pagination error handling", func(t *testing.T) {
			mockClient := NewMockGraphqlClient()

			// First page succeeds
			mockClient.GetGroupsByIDsFunc.PushReturn(&gql.GetGroupsByIDsResponse{
				Groups: gql.GetGroupsByIDsGroupsGroupConnection{
					GroupConnectionFields: gql.GroupConnectionFields{
						Nodes: []gql.GroupConnectionFieldsNodesGroup{
							*createTestGroup("gid://gitlab/Group/1", "group1"),
						},
						PageInfo: gql.GroupConnectionFieldsPageInfo{
							PageInfoFields: gql.PageInfoFields{
								HasNextPage: true,
								EndCursor:   "cursor1",
							},
						},
						Count: 2,
					},
				},
			}, nil)

			// Second page fails
			mockClient.GetGroupsByIDsFunc.PushReturn(nil, errors.Wrap(assert.AnError, "GraphQL error"))

			c := newTestClientWithGraphQLMock(t, mockClient)
			_, err := c.GetGroupsByIDs(ctx, []string{"1", "2"})
			require.Error(t, err)
			require.ErrorIs(t, err, assert.AnError)

			// Should have made two calls before failing
			calls := mockClient.GetGroupsByIDsFunc.History()
			require.Len(t, calls, 2)
		})

		t.Run("extreme pagination", func(t *testing.T) {
			mockClient := NewMockGraphqlClient()

			// Create a scenario with many pages to test safety bounds

			for i := range 100 {
				hasNext := i < 99 // Last page has no next page
				cursor := fmt.Sprintf("cursor%d", i+1)

				mockClient.GetGroupsByIDsFunc.PushReturn(&gql.GetGroupsByIDsResponse{
					Groups: gql.GetGroupsByIDsGroupsGroupConnection{
						GroupConnectionFields: gql.GroupConnectionFields{
							Nodes: []gql.GroupConnectionFieldsNodesGroup{
								*createTestGroup(fmt.Sprintf("gid://gitlab/Group/%d", i+1), fmt.Sprintf("group%d", i+1)),
							},
							PageInfo: gql.GroupConnectionFieldsPageInfo{
								PageInfoFields: gql.PageInfoFields{
									HasNextPage: hasNext,
									EndCursor:   cursor,
								},
							},
							Count: 100,
						},
					},
				}, nil)
			}

			c := newTestClientWithGraphQLMock(t, mockClient)
			groups, err := c.GetGroupsByIDs(ctx, []string{"1"})
			require.NoError(t, err)

			// Should collect all groups from all pages
			require.Len(t, groups, 100)

			// Should have made 100 calls
			calls := mockClient.GetGroupsByIDsFunc.History()
			require.Len(t, calls, 100)
		})

		t.Run("conversion error handling", func(t *testing.T) {
			mockClient := NewMockGraphqlClient()

			// Return a group with invalid ID that can't be converted
			mockClient.GetGroupsByIDsFunc.PushReturn(&gql.GetGroupsByIDsResponse{
				Groups: gql.GetGroupsByIDsGroupsGroupConnection{
					GroupConnectionFields: gql.GroupConnectionFields{
						Nodes: []gql.GroupConnectionFieldsNodesGroup{
							{
								GroupFields: gql.GroupFields{
									Id:          "invalid-id", // This should cause conversion error
									Name:        "group1",
									FullPath:    "group1",
									Description: "Test group",
									WebUrl:      "https://gitlab.com/group1",
									AvatarUrl:   "",
									Visibility:  "private",
								},
							},
						},
						PageInfo: gql.GroupConnectionFieldsPageInfo{
							PageInfoFields: gql.PageInfoFields{
								HasNextPage: false,
								EndCursor:   "cursor1",
							},
						},
						Count: 1,
					},
				},
			}, nil)

			c := newTestClientWithGraphQLMock(t, mockClient)
			_, err := c.GetGroupsByIDs(ctx, []string{"1"})
			require.Error(t, err)
			require.Contains(t, err.Error(), "failed to convert GraphQL group")
		})

		t.Run("empty nodes in pagination", func(t *testing.T) {
			mockClient := NewMockGraphqlClient()

			// First page has groups
			mockClient.GetGroupsByIDsFunc.PushReturn(&gql.GetGroupsByIDsResponse{
				Groups: gql.GetGroupsByIDsGroupsGroupConnection{
					GroupConnectionFields: gql.GroupConnectionFields{
						Nodes: []gql.GroupConnectionFieldsNodesGroup{
							*createTestGroup("gid://gitlab/Group/1", "group1"),
						},
						PageInfo: gql.GroupConnectionFieldsPageInfo{
							PageInfoFields: gql.PageInfoFields{
								HasNextPage: true,
								EndCursor:   "cursor1",
							},
						},
						Count: 2,
					},
				},
			}, nil)

			// Second page is empty but indicates more pages (edge case)
			mockClient.GetGroupsByIDsFunc.PushReturn(&gql.GetGroupsByIDsResponse{
				Groups: gql.GetGroupsByIDsGroupsGroupConnection{
					GroupConnectionFields: gql.GroupConnectionFields{
						Nodes: []gql.GroupConnectionFieldsNodesGroup{}, // Empty nodes
						PageInfo: gql.GroupConnectionFieldsPageInfo{
							PageInfoFields: gql.PageInfoFields{
								HasNextPage: true,
								EndCursor:   "cursor2",
							},
						},
						Count: 2,
					},
				},
			}, nil)

			// Third page has one group, and no next page
			mockClient.GetGroupsByIDsFunc.PushReturn(&gql.GetGroupsByIDsResponse{
				Groups: gql.GetGroupsByIDsGroupsGroupConnection{
					GroupConnectionFields: gql.GroupConnectionFields{
						Nodes: []gql.GroupConnectionFieldsNodesGroup{
							*createTestGroup("gid://gitlab/Group/2", "group2"),
						},
						PageInfo: gql.GroupConnectionFieldsPageInfo{
							PageInfoFields: gql.PageInfoFields{
								HasNextPage: false,
								EndCursor:   "cursor3",
							},
						},
						Count: 2,
					},
				},
			}, nil)

			c := newTestClientWithGraphQLMock(t, mockClient)
			groups, err := c.GetGroupsByIDs(ctx, []string{"1"})
			require.NoError(t, err)
			require.Len(t, groups, 2) // Groups from the first and third pages

			// Should have made two calls
			calls := mockClient.GetGroupsByIDsFunc.History()
			require.Len(t, calls, 3)
		})
	})
}

// newTestClientWithGraphQLMock creates a test client with a mock GraphQL client injected
func newTestClientWithGraphQLMock(t testing.TB, mockGraphQLClient *MockGraphqlClient) *Client {
	t.Helper()

	rcache.SetupForTest(t)
	redispool.SetupForTest(t, tenanttest.TestContext())

	baseURL, err := url.Parse("https://gitlab.com/")
	require.NoError(t, err)

	provider := NewClientProvider("TestMock", baseURL, nil)
	cli := provider.GetOAuthClient("")
	cli.internalRateLimiter = ratelimit.NewInstrumentedLimiter("gitlab", rate.NewLimiter(100, 10))

	// Inject the mock GraphQL client
	cli.graphqlClientSource = func(url string, doer httpcli.Doer) graphqlClient {
		return mockGraphQLClient
	}

	return cli
}

func newTestVCRClientForGroups(t testing.TB, name string) (*Client, func()) {
	t.Helper()

	rcache.SetupForTest(t)
	redispool.SetupForTest(t, tenanttest.TestContext())

	cf, save := httptestutil.NewRecorderFactory(t, update(name), name)
	doer, err := cf.Doer()
	if err != nil {
		t.Fatal(err)
	}

	baseURL, err := url.Parse("https://gitlab.com/")
	if err != nil {
		t.Fatal(err)
	}

	provider := NewClientProvider("TestVCR", baseURL, doer)

	// Try to use a token if available for VCR recording, otherwise use unauthenticated
	token := ""
	if vcrToken != nil && vcrToken.Token != "" {
		token = vcrToken.Token
	}

	cli := provider.GetOAuthClient(token)
	cli.internalRateLimiter = ratelimit.NewInstrumentedLimiter("gitlab", rate.NewLimiter(100, 10))

	return cli, save
}

