// TestClient_GetGroupsByIDs_VCR tests the GetGroupsByIDs method using VCR recordings.
// This test uses hardcoded group IDs that are known to exist in GitLab.com.
func TestClient_GetGroupsByIDs_VCR(t *testing.T) {
	cli, save := newTestVCRClientForGroups(t, "GetGroupsByIDs")
	defer save()

	ctx := tenanttest.TestContext()

	// Test group IDs discovered from GitLab.com API
	// These are real groups created for testing purposes by the sourcegraph-vcr user
	const (
		testGroupID1 = "108328765" // sourcegraph-vcr-real-group
		testGroupID2 = "108329154" // sourcegraph-vcr-real-group-2

		// GraphQL Global IDs for the same groups
		testGroupGlobalID1 = "gid://gitlab/Group/108328765"
		testGroupGlobalID2 = "gid://gitlab/Group/108329154"
	)

	t.Run("single-numeric-id", func(t *testing.T) {
		groups, err := cli.GetGroupsByIDs(ctx, []string{testGroupID1})
		if err != nil {
			t.Fatal(err)
		}

		testutil.AssertGolden(t,
			"testdata/golden/GetGroupsByIDs-VCR-single-numeric-id",
			update("GetGroupsByIDs"),
			map[string]any{
				"groups": groups,
			},
		)

		// Verify we got exactly one group
		if len(groups) != 1 {
			t.Errorf("Expected 1 group, got %d", len(groups))
		}

		if len(groups) > 0 {
			// Verify the group has expected basic properties
			group := groups[0]
			if group.ID != 108328765 {
				t.Errorf("Expected group ID 108328765, got %d", group.ID)
			}
			if group.FullPath == "" {
				t.Error("Expected non-empty FullPath")
			}
		}
	})

	t.Run("single-global-id", func(t *testing.T) {
		groups, err := cli.GetGroupsByIDs(ctx, []string{testGroupGlobalID1})
		if err != nil {
			t.Fatal(err)
		}

		testutil.AssertGolden(t,
			"testdata/golden/GetGroupsByIDs-VCR-single-global-id",
			update("GetGroupsByIDs"),
			map[string]any{
				"groups": groups,
			},
		)

		// Verify we got exactly one group
		if len(groups) != 1 {
			t.Errorf("Expected 1 group, got %d", len(groups))
		}

		if len(groups) > 0 {
			// Verify the group has expected basic properties
			group := groups[0]
			if group.ID != 108328765 {
				t.Errorf("Expected group ID 108328765, got %d", group.ID)
			}
		}
	})

	t.Run("multiple-numeric-ids", func(t *testing.T) {
		groups, err := cli.GetGroupsByIDs(ctx, []string{testGroupID1, testGroupID2})
		if err != nil {
			t.Fatal(err)
		}

		testutil.AssertGolden(t,
			"testdata/golden/GetGroupsByIDs-VCR-multiple-numeric-ids",
			update("GetGroupsByIDs"),
			map[string]any{
				"groups": groups,
			},
		)

		// Verify we got exactly two groups
		if len(groups) != 2 {
			t.Errorf("Expected 2 groups, got %d", len(groups))
		}

		// Verify both groups have expected IDs
		foundIDs := make(map[int32]bool)
		for _, group := range groups {
			foundIDs[group.ID] = true
		}

		expectedIDs := []int32{108328765, 108329154}
		for _, expectedID := range expectedIDs {
			if !foundIDs[expectedID] {
				t.Errorf("Expected to find group ID %d in results", expectedID)
			}
		}
	})

	t.Run("multiple-global-ids", func(t *testing.T) {
		groups, err := cli.GetGroupsByIDs(ctx, []string{testGroupGlobalID1, testGroupGlobalID2})
		if err != nil {
			t.Fatal(err)
		}

		testutil.AssertGolden(t,
			"testdata/golden/GetGroupsByIDs-VCR-multiple-global-ids",
			update("GetGroupsByIDs"),
			map[string]any{
				"groups": groups,
			},
		)

		// Verify we got exactly two groups
		if len(groups) != 2 {
			t.Errorf("Expected 2 groups, got %d", len(groups))
		}
	})

	t.Run("mixed-id-types", func(t *testing.T) {
		groups, err := cli.GetGroupsByIDs(ctx, []string{testGroupID1, testGroupGlobalID2})
		if err != nil {
			t.Fatal(err)
		}

		testutil.AssertGolden(t,
			"testdata/golden/GetGroupsByIDs-VCR-mixed-id-types",
			update("GetGroupsByIDs"),
			map[string]any{
				"groups": groups,
			},
		)

		// Verify we got exactly two groups
		if len(groups) != 2 {
			t.Errorf("Expected 2 groups, got %d", len(groups))
		}
	})

	t.Run("nonexistent-id", func(t *testing.T) {
		// Use a very large ID that's unlikely to exist
		groups, err := cli.GetGroupsByIDs(ctx, []string{"999999999999"})
		if err != nil {
			t.Fatal(err)
		}

		testutil.AssertGolden(t,
			"testdata/golden/GetGroupsByIDs-VCR-nonexistent-id",
			update("GetGroupsByIDs"),
			map[string]any{
				"groups": groups,
			},
		)

		// GitLab GraphQL API doesn't return an error for nonexistent IDs,
		// it just omits them from the results
		if len(groups) != 0 {
			t.Errorf("Expected 0 groups for nonexistent ID, got %d", len(groups))
		}
	})

	t.Run("partial-match", func(t *testing.T) {
		// Mix of existing and nonexistent IDs
		groups, err := cli.GetGroupsByIDs(ctx, []string{testGroupID1, "999999999999", testGroupID2})
		if err != nil {
			t.Fatal(err)
		}

		testutil.AssertGolden(t,
