func TestClient_ListUserGroups_VCR(t *testing.T) {
	cli, save := newTestVCRClientForGroups(t, "ListUserGroups")
	defer save()

	ctx := tenanttest.TestContext()

	t.Run("basic-functionality", func(t *testing.T) {
		groups, totalCount, nextCursor, err := cli.ListTopLevelUserGroups(ctx, "", 10, "")
