				"totalCount":  totalCount,
				"hasNextPage": hasNextPage,
				"nextCursor":  nextCursor,
			},
		)

		// Verify basic properties
		if len(groups) > 10 {
			t.Errorf("Expected at most 10 groups with limit 10, got %d", len(groups))
		}

		// Verify each group has required fields
		for i, group := range groups {
			if group.ID == 0 {
				t.Errorf("Group %d has empty ID", i)
			}
			if group.FullPath == "" {
				t.Errorf("Group %d has empty FullPath", i)
			}
		}
	})

	t.Run("search-for-group-without-suffix", func(t *testing.T) {
		// Search for first group by ID to ensure unique match
		groups, totalCount, nextCursor, err := cli.ListTopLevelUserGroups(ctx, "sourcegraph-vcr-real-group", 10, "")
		if err != nil {
			t.Fatal(err)
		}

		hasNextPage := nextCursor != ""
		testutil.AssertGolden(t,
			"testdata/golden/ListUserGroups-VCR-search-for-group-without-suffix",
			update("ListUserGroups"),
			map[string]any{
				"groups":      groups,
				"totalCount":  totalCount,
				"hasNextPage": hasNextPage,
				"nextCursor":  nextCursor,
			},
		)

		// Verify that exactly one group is returned
		require.Greater(t, len(groups), 1, "Expected at least 2 groups for 'sourcegraph-vcr-real-group' search, got %d", len(groups))
		for _, group := range groups {
			require.Contains(t, strings.ToLower(group.Name), strings.ToLower("sourcegraph-vcr-real-group"))
		}
	})

	t.Run("search-for-group-with-suffix", func(t *testing.T) {
		// Search for "group-2" which should return only the second group (sourcegraph-vcr-real-group-2)
		groups, totalCount, nextCursor, err := cli.ListTopLevelUserGroups(ctx, "group-2", 10, "")
		if err != nil {
			t.Fatal(err)
		}

		hasNextPage := nextCursor != ""
		testutil.AssertGolden(t,
			"testdata/golden/ListUserGroups-VCR-search-for-group-with-suffix",
			update("ListUserGroups"),
			map[string]any{
				"groups":      groups,
				"totalCount":  totalCount,
				"hasNextPage": hasNextPage,
				"nextCursor":  nextCursor,
			},
		)

		// Verify that exactly one group is returned
		require.Len(t, groups, 1, "Expected exactly 1 group for 'group-2' search, got %d", len(groups))

		// Verify it's the correct group (sourcegraph-vcr-real-group-2)
		group := groups[0]
		require.Contains(t, strings.ToLower(group.Name), strings.ToLower("sourcegraph-vcr-real-group-2"))
	})

	t.Run("pagination", func(t *testing.T) {
		// Test pagination with limit 1 to force multiple pages
		firstGroups, totalCount, nextCursor, err := cli.ListTopLevelUserGroups(ctx, "", 1, "")
		if err != nil {
			t.Fatal(err)
		}

		hasNextPage := nextCursor != ""
		testutil.AssertGolden(t,
			"testdata/golden/ListUserGroups-VCR-pagination-first-page",
			update("ListUserGroups"),
			map[string]any{
				"groups":      firstGroups,
				"totalCount":  totalCount,
				"hasNextPage": hasNextPage,
				"nextCursor":  nextCursor,
			},
		)

		// Verify first page results
		if len(firstGroups) > 1 {
			t.Errorf("Expected at most 1 group with limit 1, got %d", len(firstGroups))
		}

		require.NotEmpty(t, nextCursor, "Expected nextCursor to be non-empty for pagination")

		secondGroups, secondTotalCount, secondNextCursor, err := cli.ListTopLevelUserGroups(ctx, "", 1, nextCursor)
		if err != nil {
			t.Fatal(err)
		}

		secondHasNextPage := secondNextCursor != ""
		testutil.AssertGolden(t,
			"testdata/golden/ListUserGroups-VCR-pagination-second-page",
			update("ListUserGroups"),
			map[string]any{
				"groups":      secondGroups,
				"totalCount":  secondTotalCount,
				"hasNextPage": secondHasNextPage,
				"nextCursor":  secondNextCursor,
			},
		)

		// Verify second page results
		require.Greater(t, len(secondGroups), 0, "Expected at least 1 group on second page")

		firstGroupIds := collections.NewSet[int32]()
		for _, group := range firstGroups {
			firstGroupIds.Add(group.ID)
		}
		secondGroupIds := collections.NewSet[int32]()
		for _, group := range secondGroups {
			secondGroupIds.Add(group.ID)
		}

		require.True(t, firstGroupIds.Intersect(secondGroupIds).IsEmpty(), "expected distinct groups on each page")

		require.True(t, secondHasNextPage)

		// Verify third page results

		thirdGroups, thirdTotalCount, thirdNextCursor, err := cli.ListTopLevelUserGroups(ctx, "", 1, secondNextCursor)
		if err != nil {
			t.Fatal(err)
		}

		thirdHasNextPage := thirdNextCursor != ""
		testutil.AssertGolden(t,
			"testdata/golden/ListUserGroups-VCR-pagination-third-page",
			update("ListUserGroups"),
			map[string]any{
				"groups":      thirdGroups,
				"totalCount":  thirdTotalCount,
				"hasNextPage": thirdHasNextPage,
				"nextCursor":  thirdNextCursor,
			},
		)

		require.True(t, thirdTotalCount > 2)

		thirdGroupIds := collections.NewSet[int32]()
		for _, group := range thirdGroups {
			thirdGroupIds.Add(group.ID)
		}

		require.True(t, thirdGroupIds.Intersect(secondGroupIds).IsEmpty(), "expected distinct groups on each page")
		require.True(t, thirdGroupIds.Intersect(firstGroupIds).IsEmpty(), "expected distinct groups on each page")
	})

	t.Run("empty-results", func(t *testing.T) {
		// Search for something that shouldn't match any real groups
		groups, totalCount, nextCursor, err := cli.ListTopLevelUserGroups(ctx, "nonexistent-xyz-12345", 10, "")
		if err != nil {
			t.Fatal(err)
		}

		hasNextPage := nextCursor != ""
		testutil.AssertGolden(t,
			"testdata/golden/ListUserGroups-VCR-empty-results",
			update("ListUserGroups"),
			map[string]any{
				"groups":      groups,
				"totalCount":  totalCount,
				"hasNextPage": hasNextPage,
				"nextCursor":  nextCursor,
			},
		)

		// Verify no results
		if len(groups) != 0 {
			t.Errorf("Expected 0 groups for nonexistent search term, got %d", len(groups))
		}

		// With no results, there should be no next page
		if hasNextPage {
			t.Error("Expected hasNextPage to be false when no groups found")
		}
	})
}

