		t.Run("single page response", func(t *testing.T) {
			mockClient := NewMockGraphqlClient()

			// Setup single page response
			mockClient.GetGroupsByIDsFunc.PushReturn(&gql.GetGroupsByIDsResponse{
				Groups: gql.GetGroupsByIDsGroupsGroupConnection{
