			_, err := c.GetGroupsByIDs(ctx, []string{"1", "2"})
			require.Error(t, err)
			require.ErrorIs(t, err, assert.AnError)

			// Should have made two calls before failing
			calls := mockClient.GetGroupsByIDsFunc.History()
			require.Len(t, calls, 2)
		})

		t.Run("extreme pagination", func(t *testing.T) {
			mockClient := NewMockGraphqlClient()

