type HTTPError struct {
	code int
	body []byte
}

func NewHTTPError(code int, body []byte) HTTPError {
	return HTTPError{
		code: code,
		body: body,
	}
}

func (err HTTPError) Code() int {
	return err.code
}

func (err HTTPError) Message() string {
	var errBody struct {
		Message string `json:"message"`
	}
	// Swallow error, decoding the body as
	_ = json.Unmarshal(err.body, &errBody)
	return errBody.Message
}

func (err HTTPError) Error() string {
	return fmt.Sprintf("HTTP error status %d", err.code)
}

func (err HTTPError) Unauthorized() bool {
	return err.code == http.StatusUnauthorized
}

func (err HTTPError) Forbidden() bool {
	return err.code == http.StatusForbidden
}

func (err HTTPError) Temporary() bool {
	switch err.code {
	// Rate limit errors are temporary
	case http.StatusTooManyRequests:
		return true
	// Gateway and service errors are temporary infrastructure issues
	case http.StatusInternalServerError, http.StatusBadGateway, http.StatusServiceUnavailable, http.StatusGatewayTimeout:
		return true
	default:
		return false
	}
}

// temporaryError wraps an error and marks it as temporary.
// This is used for transient errors like HTTP/2 stream errors
// that should trigger retry logic and preserve existing permissions.
type temporaryError struct {
	error
}

func (temporaryError) Temporary() bool { return true }

func (e temporaryError) Unwrap() error { return e.error }

// isHTTP2StreamError detects HTTP/2 stream errors from GitLab.
// These are transient network errors where the server terminates the stream,
// often due to load balancing or infrastructure issues on GitLab's side.
// This handles both CANCEL and INTERNAL_ERROR stream terminations.
func isHTTP2StreamError(err error) bool {
	s := strings.ToLower(err.Error())
	if !strings.Contains(s, "stream error") {
		return false
	}
	// Match common HTTP/2 stream error codes that indicate transient issues
	return strings.Contains(s, "cancel") || strings.Contains(s, "internal_error")
}

// HTTPErrorCode returns err's HTTP status code, if it is an HTTP error from
// this package. Otherwise it returns 0.
func HTTPErrorCode(err error) int {
	var e HTTPError
	if errors.As(err, &e) {
		return e.Code()
	}

	return 0
}

// IsNotFound reports whether err is a GitLab API error of type NOT_FOUND, the equivalent cached
// response error, or HTTP 404.
func IsNotFound(err error) bool {
	return errors.HasType[*ProjectNotFoundError](err) ||
		errors.Is(err, ErrMergeRequestNotFound) ||
		HTTPErrorCode(err) == http.StatusNotFound
}

// IsOAuthToken reports whether err indicates an OAuth token was used where a Personal Access Token is expected.
func IsOAuthToken(err error) bool {
	return errors.HasType[*OAuthTokenError](err) ||
		errors.Is(err, ErrOAuthToken)
}

