	if err != nil {
		return nil, err
	}

	var group Group
	_, _, err = c.do(ctx, req, &group)
	if err != nil {
		return nil, err
	}

	return &group, nil
}

// GetGroupsByIDs retrieves multiple groups by their IDs using the GitLab GraphQL API.
// This method supports batch fetching up to 50 groups at a time to align with GitLab API limits.
// Group IDs should be provided as GraphQL Global IDs (e.g., "gid://gitlab/Group/1234") or
