with open('/workspace/cmd/frontend/internal/auth/gitlaboauth/session.go', 'r') as f:
    content = f.read()

# Replace the old verifyUserGroups function with a new one that uses GetGroupByPath
old_func = '''// verifyUserGroups checks whether the authenticated user belongs to one of the GitLab groups when the allowGroups option is set.
func (s *sessionIssuerHelper) verifyUserGroups(ctx context.Context, glClient *gitlab.Client) (bool, error) {
\tif len(s.allowGroups) == 0 {
\t\treturn true, nil
\t}

\tallowed := make(map[string]bool, len(s.allowGroups))
\tfor _, group := range s.allowGroups {
\t\tallowed[group] = true
\t}

\tvar err error
\tvar gitlabGroups []*gitlab.Group
\thasNextPage := true

\tfor page := 1; hasNextPage; page++ {
\t\tgitlabGroups, hasNextPage, err = glClient.ListGroups(ctx, page)
\t\tif err != nil {
\t\t\treturn false, err
\t\t}

\t\t// Check the full path instead of name so we can better handle subgroups.
\t\tfor _, glGroup := range gitlabGroups {
\t\t\tif allowed[glGroup.FullPath] {
\t\t\t\treturn true, nil
\t\t\t}
\t\t}
\t}

\treturn false, nil
}'''

new_func = '''// verifyUserGroups checks whether the authenticated user belongs to one of the GitLab groups
// when the allowGroups option is set. It uses targeted per-group API calls instead of
// paginating all user groups, avoiding rate limiting for users with many group memberships.
func (s *sessionIssuerHelper) verifyUserGroups(ctx context.Context, glClient *gitlab.Client) (bool, error) {
\tif len(s.allowGroups) == 0 {
\t\treturn true, nil
\t}

\tfor _, groupPath := range s.allowGroups {
\t\t_, err := glClient.GetGroupByPath(ctx, groupPath)
\t\tif err != nil {
\t\t\t// 404 or 403 means the user doesn't have access to this group (not a member).
\t\t\t// Continue checking other allowed groups.
\t\t\tif code := gitlab.HTTPErrorCode(err); code == http.StatusNotFound || code == http.StatusForbidden {
\t\t\t\tcontinue
\t\t\t}
\t\t\treturn false, err
\t\t}
\t\treturn true, nil
\t}

\treturn false, nil
}'''

content = content.replace(old_func, new_func)

with open('/tmp/overlay/cmd/frontend/internal/auth/gitlaboauth/session.go', 'w') as f:
    f.write(content)

print('session.go written')
assert 'GetGroupByPath' in content
assert 'ListGroups' not in content
print('OK')
EOF

