     - Contains `verifyUserGroups` which is the core function to change
     - Current implementation iterates ALL groups via `ListGroups` pagination
     - New implementation iterates `allowGroups` list and calls `GetGroupByPath` per group
     ```go
     // OLD:
     func (s *sessionIssuerHelper) verifyUserGroups(ctx context.Context, glClient *gitlab.Client) (bool, error) {
         if len(s.allowGroups) == 0 {
             return true, nil
         }
         allowed := make(map[string]bool, len(s.allowGroups))
         for _, group := range s.allowGroups {
             allowed[group] = true
         }
         var err error
         var gitlabGroups []*gitlab.Group
         hasNextPage := true
         for page := 1; hasNextPage; page++ {
             gitlabGroups, hasNextPage, err = glClient.ListGroups(ctx, page)
             if err != nil {
                 return false, err
             }
             for _, glGroup := range gitlabGroups {
                 if allowed[glGroup.FullPath] {
                     return true, nil
                 }
             }
         }
         return false, nil
     }

     // NEW (in /tmp/overlay/cmd/frontend/internal/auth/gitlaboauth/session.go):
     func (s *sessionIssuerHelper) verifyUserGroups(ctx context.Context, glClient *gitlab.Client) (bool, error) {
         if len(s.allowGroups) == 0 {
             return true, nil
         }
         for _, groupPath := range s.allowGroups {
             _, err := glClient.GetGroupByPath(ctx, groupPath)
             if err != nil {
                 // 404 or 403 means the user doesn't have access to this group (not a member).
                 // Continue checking other allowed groups.
                 if code := gitlab.HTTPErrorCode(err); code == http.StatusNotFound || code == http.StatusForbidden {
                     continue
                 }
                 return false, err
             }
             return true, nil
         }
         return false, nil
     }
     ```

