     // GetGroupByPath retrieves a group by its full path. The path may include subgroup segments
     // (e.g., "mygroup/mysubgroup"). Returns an error if the group is not found or the
     // authenticated user does not have access to it.
     func (c *Client) GetGroupByPath(ctx context.Context, path string) (*Group, error) {
         if MockGetGroupByPath != nil {
             return MockGetGroupByPath(c, ctx, path)
         }
         encodedPath := url.PathEscape(path)
         req, err := http.NewRequestWithContext(ctx, "GET", fmt.Sprintf("groups/%s", encodedPath), nil)
         if err != nil {
             return nil, err
         }
         var group Group
         _, _, err = c.do(ctx, req, &group)
         if err != nil {
             return nil, err
         }
         return &group, nil
     }
     ```
