// verifyUserGroups checks whether the authenticated user belongs to one of the GitLab groups
// when the allowGroups option is set. It uses targeted per-group API calls instead of
// paginating all user groups, avoiding rate limiting for users with many group memberships.
func (s *sessionIssuerHelper) verifyUserGroups(ctx context.Context, glClient *gitlab.Client) (bool, error) {
	if len(s.allowGroups) == 0 {
		return true, nil
	}

	for _, groupPath := range s.allowGroups {
		_, err := glClient.GetGroupByPath(ctx, groupPath)
		if err != nil {
			// 404 or 403 means the user doesn't have access to this group (not a member).
			// Continue checking other allowed groups.
			if code := gitlab.HTTPErrorCode(err); code == http.StatusNotFound || code == http.StatusForbidden {
				continue
			}
			return false, err
		}
		return true, nil
	}

	return false, nil
}

